    useEffect(() => {
    if (tasks.length === 0 && setTasks) {
      setTasks(INITIAL_TASKS);
    }
  }, []);



    const handleAddTask = (newTask: Task) => {
    if (setTasks) {

      setTasks([...tasks, newTask]);
    }
  };


  const handleToggle = (id: number) => {
    if (setTasks) {
      setTasks(tasks.map(t => 
        t.id === id ? { ...t, completed: !t.completed } : t
